1. **Fork a new process**: This creates a new process that is a copy of the current process.
2. **Redirect file descriptors**: In the child process, you can redirect the standard input and output file descriptors to connect them to a file or pipe.
3. **Execute a new program**: Use `exec()` to replace the current process image with a new process image.

Below is an example that demonstrates these steps:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>

int main() {
    int fd[2];  // File descriptor for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        perror("pipe");
        exit(EXIT_FAILURE);
    }

    // Fork a new process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        close(fd[0]);
        close(fd[1]);
        exit(EXIT_FAILURE);
    } else if (pid > 0) {  // Parent process
        // Close the unused ends of the pipe
        close(fd[0]);

        // Redirect standard input to the write end of the pipe
        dup2(fd[1], STDIN_FILENO);
        close(fd[1]);

        // Wait for the child to finish
        wait(NULL);
    } else {  // Child process
        // Close the unused ends of the pipe
        close(fd[1]);

        // Redirect standard output to the read end of the pipe
        dup2(fd[0], STDOUT_FILENO);
        close(fd[0]);

        // Execute a new program
        execlp("/bin/echo", "echo", "Hello, World!", (char*)0);

        // If execlp fails, handle the error
        perror("execlp");
        exit(EXIT_FAILURE);
    }

    return 0;
}
```

